import React, { useState, useEffect } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, Loader2 } from 'lucide-react';
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const COORDS_LOCAL = { lat: -26.732479, lon: -65.267028 }; 

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); // tienda, proceso, historial
  const [ofertas, setOfertas] = useState([]);
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  
  // Ubicación
  const [busqueda, setBusqueda] = useState("");
  const [sugerencias, setSugerencias] = useState([]);
  const [distanciaReal, setDistanciaReal] = useState(0);
  const [cargando, setCargando] = useState(false);

  useEffect(() => {
    // Carga de ofertas
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acc = [];
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      acc = [...acc, ...ofs.map(o => ({ ...o, nombreLocal: l.nombre }))];
    });
    setOfertas(acc);

    // Carga de historial
    const historial = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    setPedidos(historial);
  }, []);

  const buscarDireccion = async (val) => {
    setBusqueda(val);
    if (val.length < 5) return setSugerencias([]);
    setCargando(true);
    try {
      const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${val}&countrycodes=ar&limit=5&addressdetails=1`);
      const data = await res.json();
      setSugerencias(data);
    } catch (e) { console.error(e); }
    finally { setCargando(false); }
  };

  const seleccionarDireccion = (item) => {
    const d = calcularDistanciaReal(parseFloat(item.lat), parseFloat(item.lon), COORDS_LOCAL.lat, COORDS_LOCAL.lon);
    setDistanciaReal(d);
    setBusqueda(`${item.address.road || ''} ${item.address.house_number || ''}, ${item.address.city || item.address.town || ''}`);
    setSugerencias([]);
  };

  const handlePago = (total) => {
    const nuevo = {
      id: `PED-${Date.now()}`,
      total,
      fecha: new Date().toLocaleString(),
      estado: 'proceso',
      distancia: distanciaReal,
      items: [...cart]
    };
    const listaActualizada = [nuevo, ...pedidos];
    setPedidos(listaActualizada);
    localStorage.setItem('historial-pedidos', JSON.stringify(listaActualizada));
    setCart([]);
    setTab('proceso');
  };

  const finalizarPedido = (id) => {
    const actualizados = pedidos.map(p => p.id === id ? { ...p, estado: 'completado' } : p);
    setPedidos(actualizados);
    localStorage.setItem('historial-pedidos', JSON.stringify(actualizados));
  };

  return (
    <div style={panelLayout}>
      {/* NAVEGACIÓN LATERAL */}
      <div style={sidebar}>
        <h2 style={{color: '#e67e22', marginBottom: '40px'}}>🛒 MiApp</h2>
        <button onClick={() => setTab('tienda')} style={tab === 'tienda' ? btnNavActive : btnNav}><ShoppingBag size={18}/> Tienda</button>
        <button onClick={() => setTab('proceso')} style={tab === 'proceso' ? btnNavActive : btnNav}>
          <Clock size={18}/> En Proceso {pedidos.filter(p => p.estado === 'proceso').length > 0 && <span style={badge}>{pedidos.filter(p => p.estado === 'proceso').length}</span>}
        </button>
        <button onClick={() => setTab('historial')} style={tab === 'historial' ? btnNavActive : btnNav}><CheckCircle size={18}/> Historial</button>
      </div>

      {/* CONTENIDO PRINCIPAL */}
      <div style={mainContent}>
        {tab === 'tienda' && (
          <div style={{display: 'flex', gap: '30px'}}>
            <div style={{flex: 1}}>
              <div style={searchBar}>
                <MapPin size={20} color="#e67e22" />
                <input style={input} placeholder="Tu dirección para el envío..." value={busqueda} onChange={(e) => buscarDireccion(e.target.value)} />
                {cargando && <Loader2 size={18} className="animate-spin" />}
                {sugerencias.length > 0 && (
                  <div style={dropdown}>
                    {sugerencias.map((s, i) => (
                      <div key={i} style={sugItem} onClick={() => seleccionarDireccion(s)}>
                        {s.display_name.slice(0, 50)}...
                      </div>
                    ))}
                  </div>
                )}
              </div>
              <div style={grid}>
                {ofertas.map(o => (
                  <div key={o.id} style={cardOferta}>
                    <img src={o.imagen} style={imgStyle} alt="" />
                    <div style={{padding: '12px'}}>
                      <small>{o.nombreLocal}</small>
                      <h4 style={{margin: '5px 0'}}>{o.producto}</h4>
                      <button style={btnAdd} onClick={() => setCart([...cart, o])}>Agregar ${o.precioNuevo}</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <Carrito cart={cart} setCart={setCart} distanciaReal={distanciaReal} onCheckout={handlePago} />
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centeredContainer}>
            <h3>Pedidos en curso</h3>
            {pedidos.filter(p => p.estado === 'proceso').length === 0 ? <p>No hay envíos activos.</p> :
              pedidos.filter(p => p.estado === 'proceso').map(p => <SeguimientoPedido key={p.id} pedido={p} onFinalizar={finalizarPedido} />)
            }
          </div>
        )}

        {tab === 'historial' && (
          <div style={centeredContainer}>
            <h3>Pedidos Realizados</h3>
            <div style={historialList}>
              {pedidos.filter(p => p.estado === 'completado').map(p => (
                <div key={p.id} style={historialItem}>
                  <span>{p.fecha}</span>
                  <strong>${p.total}</strong>
                  <span style={{color: '#27ae60'}}>● Completado</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const panelLayout = { display: 'flex', minHeight: '100vh', background: '#f8fafc' };
const sidebar = { width: '250px', background: '#1e293b', padding: '30px 20px', display: 'flex', flexDirection: 'column', gap: '10px' };
const btnNav = { display: 'flex', alignItems: 'center', gap: '10px', padding: '12px', background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer', textAlign: 'left', borderRadius: '10px', width: '100%' };
const btnNavActive = { ...btnNav, background: '#334155', color: 'white' };
const badge = { background: '#e67e22', color: 'white', borderRadius: '50%', padding: '2px 7px', fontSize: '0.7rem', marginLeft: 'auto' };
const mainContent = { flex: 1, padding: '40px' };
const searchBar = { display: 'flex', alignItems: 'center', background: 'white', padding: '12px 20px', borderRadius: '15px', position: 'relative', border: '1px solid #e2e8f0', marginBottom: '25px' };
const input = { flex: 1, border: 'none', outline: 'none', marginLeft: '10px' };
const dropdown = { position: 'absolute', top: '100%', left: 0, right: 0, background: 'white', zIndex: 10, border: '1px solid #e2e8f0', borderRadius: '10px', overflow: 'hidden' };
const sugItem = { padding: '10px 20px', cursor: 'pointer', borderBottom: '1px solid #f1f5f9' };
const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const cardOferta = { background: 'white', borderRadius: '15px', overflow: 'hidden', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '120px', objectFit: 'cover' };
